var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"젠장, 탄약은 이걸로 끝이야.","JPN":"くそ、これで弾薬は最後だ。","ENG":"Damn, that was my last round.","TWN":"可惡，彈藥就此用盡了。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"투척 나이프는 5자루… 겨우 이걸로 녀석들에게서 벗어날 수 있을까……?","JPN":"投げナイフは5本……こんな貧弱な装備で、やつらから逃れられるのか……？","ENG":"Five throwing knives left... Is that really enough to shake them off...?","TWN":"投擲刀只有5把……僅憑這些能從那些傢伙手中逃脫嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카, 언제까지 뛰어야 하는데요!","JPN":"ライカ、いつまで走ればいいの！","ENG":"Laika, how much longer do we have to run?!","TWN":"萊卡，我們要跑到什麼時候啊！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이제 그 검은 옷 메이드들은 그림자도 안 보인다고요……!","JPN":"さっきの黒いメイドたち、もう影も見えないけど！","ENG":"Those maids in black are long gone...!","TWN":"現在那些黑衣女僕連影子都看不見了……！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"잔말 말고 계속 뛰기나 해!","JPN":"つべこべ言わずに走れ！","ENG":"Shut up and run!","TWN":"別廢話，繼續跳！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"겨우 이 정도 벗어났다고, 저 집요한 변태들을 따돌릴 수 있을 리가 없잖아……!","JPN":"たったこれぐらいで、あのしつこい変態たちを振り切れると思っちゃだめだ！","ENG":"Just because they're out of sight doesn't mean we're safe. Those obsessive freaks never give up that easily...!","TWN":"才甩開這麼一點，怎麼可能甩掉那些執著的變態啊……！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"변태들이라니……?","JPN":"変態たち……？","ENG":"Freaks...?","TWN":"變態們……？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"대체 저 메이드들 정체가 뭔데 그래요?","JPN":"あのメイドたち、いったい何なの？","ENG":"Who are those maids anyway?","TWN":"那些女僕到底是什麼來頭？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하아, 하아…! 잘 들어, 꼬맹아.","JPN":"はあ、はあ……！　よく聞けよ、おこちゃま。","ENG":"Haha...! Listen up, kid.","TWN":"哈啊，哈啊！聽好了，小鬼。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"언더그라운드… 통칭, 뒷골목에는 잘못 엮였다간, 평생이 피곤해지는 조직이 세 군데 있어.","JPN":"アンダーグラウンド……通称裏路地には、下手に関わったら一生苦労する組織が3つあるんだ。","ENG":"In the Underground—you know, the back alley—there are three names you never want to mess with unless you want a lifetime of regret.","TWN":"地下世界……俗稱後街，有三個組織，一旦牽扯進去，就會一輩子麻煩不斷。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"세 군데라고요?","JPN":"3つ？","ENG":"Three names?","TWN":"三個地方？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"첫 번째는 <color=#ffd34c>성황청의 미친개들</color>…….","JPN":"1つ目は<color=#ffd34c>聖皇庁の狂犬たち</color>……","ENG":"First up, the <color=#ffd34c>Mad Dogs of the Holy Curia</color>...","TWN":"第一個是<color=#ffd34c>聖皇廳的瘋狗們</color>……"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이 광신도 자식들이랑 종교 문제로 엮였다간, 지옥 끝까지 쫓아다닌다고.","JPN":"あの狂信徒のやつらと宗教がらみで関わったら、地獄の果てまで追いかけられる。","ENG":"If you ever get tangled up with those zealots over some religious issue, they'll hunt you to the ends of hell.","TWN":"如果和這些狂熱使徒在宗教問題上糾纏不清，他們會追到地獄盡頭。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"성유물 회수, 기적 심사, 이단 심판……. 온갖 그럴싸한 수식어는 다 갖다 붙이지만…….","JPN":"聖遺物の回収、奇跡審査、異端審問……それっぽい単語で飾ってるけど……","ENG":"Holy Relic retrieval, miracle evaluation, heresy trials... They've got a holy name for every shady job.","TWN":"神器回收、奇蹟審查、異端審判……各種聽起來很厲害的詞都用上了……"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"결국, 이 자식들의 본질은 종교로 이미지 세탁한 거대 마피아 조직과 다를 바 없거든.","JPN":"結局やつらの本質は、宗教の皮をかぶった巨大マフィア組織なんだ。","ENG":"But when you strip away the robes, they're just a glorified mafia with a Bible in hand.","TWN":"最後，這些傢伙的本質和用宗教洗白自身形象的龐大黑手黨組織沒有什麼區別。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐, 그나마 나은 점은 구색이 종교 집단이라, 그 영역만 건드리지 않으면 녀석들을 마주칠 일은 거의 없다는 거지.","JPN":"まあ、せめてもの救いは……一応宗教団体だから、テリトリーさえ守ればやつらに遭遇することはないってことだな。","ENG":"Fortunately, since they cling to their religious image, you won't see much of them unless you step on their territory.","TWN":"嗯，稍微好一點的是，他們是宗教團體，只要不觸碰到他們的領域，幾乎不會遇到他們。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"두 번째는 <color=#ffd34c>로터스에 사는 벌레들</color>…….","JPN":"2つ目は<color=#ffd34c>ロータスの虫たち</color>……","ENG":"Second, the <color=#ffd34c>bugs that infest Lotus</color>...","TWN":"第二個是<color=#ffd34c>洛德斯裡的蟲子們</color>……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"기억 나? 이쪽은 우리랑도 조금 연이 있는데.","JPN":"覚えてる？　こっちは私たちとも多少縁があるんだけど。","ENG":"Remember? We've had a bit of history with them.","TWN":"記得嗎？這邊和我們也有點關係。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그러고보니…….","JPN":"そういえば……","ENG":"Oh, right...","TWN":"我想起來了……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"우리를 도와주었던 초원 씨가 거미 앰블럼을 붙이고 있었죠?","JPN":"私たちを助けてくれたナオさんが、クモのエンブレムをつけてたわね？","ENG":"Chowon, who helped us, was wearing a spider emblem, wasn't she?","TWN":"幫助過我們的初源戴著蜘蛛徽章，對吧？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래. 거미는 원래 하나의 조직이었는데, 수년 전에 내부 분쟁으로 인해 와해되었지.","JPN":"そう。クモはもともと1つの組織だったけど、数年前に内輪もめで瓦解した。","ENG":"Yeah. The Arachnid used to be one unified organization, but a few years back, they fell apart after some nasty infighting.","TWN":"對。蜘蛛原本是一個組織，但在數年前因內部紛爭而解散了。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그 뒤로 거미에게 영향을 받아서, 생겨난 점조직들이 로터스에 사는 벌레들이야.","JPN":"その後、クモの後を継ぐようにして立ち上げられた分散型組織群が、ロータスの虫たちさ。","ENG":"All that's left are little offshoots scattered around Lotus, remnants inspired by the Arachnid. The bugs that infest Lotus...","TWN":"之後受到蜘蛛的影響，產生了在洛德斯生活的蟲子們。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"거미가 워낙 막장 집단으로 유명하다 보니, 와해된 뒤에도 여기저기서 이름이 들리더라고.","JPN":"クモの悪名が高いから、瓦解した後もあちこちから名前を聞くんだよね。","ENG":"The Arachnid's name was so infamous that even after the group collapsed, the name kept popping up.","TWN":"因為蜘蛛是出了名的混亂組織，所以即使解散了，到處還是能聽到他們的名字"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"물론, 그중 대부분은 이름이나 빌린 짝퉁들이지만…….","JPN":"もちろん、ほとんどは名ばかりの偽物だけど……","ENG":"Of course, most of them now are just cheap knock-offs riding on the brand.","TWN":"當然，其中大部分都是借來的假名或仿冒品……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};